pub const ext = @import("ext.zig");
const nm = @This();

const std = @import("std");
const compat = @import("compat");
const gio = @import("gio2");
const gobject = @import("gobject2");
const glib = @import("glib2");
const gmodule = @import("gmodule2");
pub const AccessPoint = opaque {
    pub const Parent = nm.Object;
    pub const Implements = [_]type{};
    pub const Class = nm.AccessPointClass;
    pub const virtual_methods = struct {};

    pub const properties = struct {
        /// The channel bandwidth announced by the AP in MHz.
        pub const bandwidth = struct {
            pub const name = "bandwidth";

            pub const Type = c_uint;
        };

        /// The BSSID of the access point.
        pub const bssid = struct {
            pub const name = "bssid";

            pub const Type = ?[*:0]u8;
        };

        /// The flags of the access point.
        pub const flags = struct {
            pub const name = "flags";

            pub const Type = nm.@"80211ApFlags";
        };

        /// The frequency of the access point.
        pub const frequency = struct {
            pub const name = "frequency";

            pub const Type = c_uint;
        };

        /// Alias for `nm.AccessPoint.properties.bssid`.
        pub const hw_address = struct {
            pub const name = "hw-address";

            pub const Type = ?[*:0]u8;
        };

        /// The timestamp (in CLOCK_BOOTTIME seconds) for the last time the
        /// access point was found in scan results.  A value of -1 means the
        /// access point has not been found in a scan.
        pub const last_seen = struct {
            pub const name = "last-seen";

            pub const Type = c_int;
        };

        /// The maximum bit rate of the access point in kbit/s.
        pub const max_bitrate = struct {
            pub const name = "max-bitrate";

            pub const Type = c_uint;
        };

        /// The mode of the access point; either "infrastructure" (a central
        /// coordinator of the wireless network allowing clients to connect) or
        /// "ad-hoc" (a network with no central controller).
        pub const mode = struct {
            pub const name = "mode";

            pub const Type = nm.@"80211Mode";
        };

        /// The RSN flags of the access point.
        pub const rsn_flags = struct {
            pub const name = "rsn-flags";

            pub const Type = nm.@"80211ApSecurityFlags";
        };

        /// The SSID of the access point, or `NULL` if it is not known.
        pub const ssid = struct {
            pub const name = "ssid";

            pub const Type = ?*glib.Bytes;
        };

        /// The current signal strength of the access point.
        pub const strength = struct {
            pub const name = "strength";

            pub const Type = u8;
        };

        /// The WPA flags of the access point.
        pub const wpa_flags = struct {
            pub const name = "wpa-flags";

            pub const Type = nm.@"80211ApSecurityFlags";
        };
    };

    pub const signals = struct {};

    /// Validates a given connection against a given Wi-Fi access point to ensure that
    /// the connection may be activated with that AP.  The connection must match the
    /// `ap`'s SSID, (if given) BSSID, and other attributes like security settings,
    /// channel, band, etc.
    extern fn nm_access_point_connection_valid(p_ap: *AccessPoint, p_connection: *nm.Connection) c_int;
    pub const connectionValid = nm_access_point_connection_valid;

    /// Filters a given array of connections for a given `nm.AccessPoint` object and
    /// returns connections which may be activated with the access point.  Any
    /// returned connections will match the `ap`'s SSID and (if given) BSSID and
    /// other attributes like security settings, channel, etc.
    ///
    /// To obtain the list of connections that are compatible with this access point,
    /// use `nm.Client.getConnections` and then filter the returned list for a given
    /// `nm.Device` using `nm.Device.filterConnections` and finally filter that list
    /// with this function.
    extern fn nm_access_point_filter_connections(p_ap: *AccessPoint, p_connections: *const glib.PtrArray) *glib.PtrArray;
    pub const filterConnections = nm_access_point_filter_connections;

    /// Gets the bandwidth advertised by the access point in MHz.
    extern fn nm_access_point_get_bandwidth(p_ap: *AccessPoint) u32;
    pub const getBandwidth = nm_access_point_get_bandwidth;

    /// Gets the Basic Service Set ID (BSSID) of the Wi-Fi access point.
    extern fn nm_access_point_get_bssid(p_ap: *AccessPoint) [*:0]const u8;
    pub const getBssid = nm_access_point_get_bssid;

    /// Gets the flags of the access point.
    extern fn nm_access_point_get_flags(p_ap: *AccessPoint) nm.@"80211ApFlags";
    pub const getFlags = nm_access_point_get_flags;

    /// Gets the frequency of the access point in MHz.
    extern fn nm_access_point_get_frequency(p_ap: *AccessPoint) u32;
    pub const getFrequency = nm_access_point_get_frequency;

    /// Returns the timestamp (in CLOCK_BOOTTIME seconds) for the last time the
    /// access point was found in scan results.  A value of -1 means the access
    /// point has not been found in a scan.
    extern fn nm_access_point_get_last_seen(p_ap: *AccessPoint) c_int;
    pub const getLastSeen = nm_access_point_get_last_seen;

    /// Gets the maximum bit rate of the access point in kbit/s.
    extern fn nm_access_point_get_max_bitrate(p_ap: *AccessPoint) u32;
    pub const getMaxBitrate = nm_access_point_get_max_bitrate;

    /// Gets the mode of the access point.
    extern fn nm_access_point_get_mode(p_ap: *AccessPoint) nm.@"80211Mode";
    pub const getMode = nm_access_point_get_mode;

    /// Gets the RSN (Robust Secure Network, ie WPA version 2) flags of the access
    /// point.
    extern fn nm_access_point_get_rsn_flags(p_ap: *AccessPoint) nm.@"80211ApSecurityFlags";
    pub const getRsnFlags = nm_access_point_get_rsn_flags;

    /// Gets the SSID of the access point.
    extern fn nm_access_point_get_ssid(p_ap: *AccessPoint) *glib.Bytes;
    pub const getSsid = nm_access_point_get_ssid;

    /// Gets the current signal strength of the access point as a percentage.
    extern fn nm_access_point_get_strength(p_ap: *AccessPoint) u8;
    pub const getStrength = nm_access_point_get_strength;

    /// Gets the WPA (version 1) flags of the access point.
    extern fn nm_access_point_get_wpa_flags(p_ap: *AccessPoint) nm.@"80211ApSecurityFlags";
    pub const getWpaFlags = nm_access_point_get_wpa_flags;

    extern fn nm_access_point_get_type() usize;
    pub const getGObjectType = nm_access_point_get_type;

    extern fn g_object_ref(p_self: *nm.AccessPoint) void;
    pub const ref = g_object_ref;

    extern fn g_object_unref(p_self: *nm.AccessPoint) void;
    pub const unref = g_object_unref;

    pub fn as(p_instance: *AccessPoint, comptime P_T: type) *P_T {
        return gobject.ext.as(P_T, p_instance);
    }

    test {
        @setEvalBranchQuota(100_000);
        std.testing.refAllDecls(@This());
    }
};

pub const ActiveConnection = opaque {
    pub const Parent = nm.Object;
    pub const Implements = [_]type{};
    pub const Class = nm.ActiveConnectionClass;
    pub const virtual_methods = struct {};

    pub const properties = struct {
        /// The connection that this is an active instance of.
        pub const connection = struct {
            pub const name = "connection";

            pub const Type = ?*nm.RemoteConnection;
        };

        /// The controller device if one exists. This replaces the deprecated
        /// "master" property.
        pub const controller = struct {
            pub const name = "controller";

            pub const Type = ?*nm.Device;
        };

        /// Whether the active connection is the default IPv4 one.
        pub const default = struct {
            pub const name = "default";

            pub const Type = c_int;
        };

        /// Whether the active connection is the default IPv6 one.
        pub const default6 = struct {
            pub const name = "default6";

            pub const Type = c_int;
        };

        /// The devices of the active connection.
        pub const devices = struct {
            pub const name = "devices";

            pub const Type = ?[*]*nm.Device;
        };

        /// The IPv4 `nm.DhcpConfig` of the connection.
        pub const dhcp4_config = struct {
            pub const name = "dhcp4-config";

            pub const Type = ?*nm.DhcpConfig;
        };

        /// The IPv6 `nm.DhcpConfig` of the connection.
        pub const dhcp6_config = struct {
            pub const name = "dhcp6-config";

            pub const Type = ?*nm.DhcpConfig;
        };

        /// The active connection's ID
        pub const id = struct {
            pub const name = "id";

            pub const Type = ?[*:0]u8;
        };

        /// The IPv4 `nm.IPConfig` of the connection.
        pub const ip4_config = struct {
            pub const name = "ip4-config";

            pub const Type = ?*nm.IPConfig;
        };

        /// The IPv6 `nm.IPConfig` of the connection.
        pub const ip6_config = struct {
            pub const name = "ip6-config";

            pub const Type = ?*nm.IPConfig;
        };

        /// The controller device if one exists. Replaced by the "controller" property.
        pub const master = struct {
            pub const name = "master";

            pub const Type = ?*nm.Device;
        };

        /// The path to the "specific object" of the active connection; see
        /// `nm.ActiveConnection.getSpecificObjectPath` for more details.
        pub const specific_object_path = struct {
            pub const name = "specific-object-path";

            pub const Type = ?[*:0]u8;
        };

        /// The state of the active connection.
        pub const state = struct {
            pub const name = "state";

            pub const Type = nm.ActiveConnectionState;
        };

        /// The state flags of the active connection.
        pub const state_flags = struct {
            pub const name = "state-flags";

            pub const Type = c_uint;
        };

        /// The active connection's type
        pub const @"type" = struct {
            pub const name = "type";

            pub const Type = ?[*:0]u8;
        };

        /// The active connection's UUID
        pub const uuid = struct {
            pub const name = "uuid";

            pub const Type = ?[*:0]u8;
        };

        /// Whether the active connection is a VPN connection.
        pub const vpn = struct {
            pub const name = "vpn";

            pub const Type = c_int;
        };
    };

    pub const signals = struct {
        pub const state_changed = struct {
            pub const name = "state-changed";

            pub fn connect(p_instance: anytype, comptime P_Data: type, p_callback: *const fn (@TypeOf(p_instance), p_state: c_uint, p_reason: c_uint, P_Data) callconv(.c) void, p_data: P_Data, p_options: gobject.ext.ConnectSignalOptions(P_Data)) c_ulong {
                return gobject.signalConnectClosureById(
                    @ptrCast(@alignCast(gobject.ext.as(ActiveConnection, p_instance))),
                    gobject.signalLookup("state-changed", ActiveConnection.getGObjectType()),
                    glib.quarkFromString(p_options.detail orelse null),
                    gobject.CClosure.new(@ptrCast(p_callback), p_data, @ptrCast(p_options.destroyData)),
                    @intFromBool(p_options.after),
                );
            }
        };
    };

    /// Gets the `nm.RemoteConnection` associated with `connection`.
    extern fn nm_active_connection_get_connection(p_connection: *ActiveConnection) *nm.RemoteConnection;
    pub const getConnection = nm_active_connection_get_connection;

    /// Gets the `nm.Connection`'s type.
    extern fn nm_active_connection_get_connection_type(p_connection: *ActiveConnection) [*:0]const u8;
    pub const getConnectionType = nm_active_connection_get_connection_type;

    /// Gets the controller `nm.Device` of the connection. This replaces the
    /// deprecated `nm.ActiveConnection.getMaster` method.
    extern fn nm_active_connection_get_controller(p_connection: *ActiveConnection) ?*anyopaque;
    pub const getController = nm_active_connection_get_controller;

    /// Whether the active connection is the default IPv4 one (that is, is used for
    /// the default IPv4 route and DNS information).
    extern fn nm_active_connection_get_default(p_connection: *ActiveConnection) c_int;
    pub const getDefault = nm_active_connection_get_default;

    /// Whether the active connection is the default IPv6 one (that is, is used for
    /// the default IPv6 route and DNS information).
    extern fn nm_active_connection_get_default6(p_connection: *ActiveConnection) c_int;
    pub const getDefault6 = nm_active_connection_get_default6;

    /// Gets the `NMDevices` used for the active connections.
    extern fn nm_active_connection_get_devices(p_connection: *ActiveConnection) *const glib.PtrArray;
    pub const getDevices = nm_active_connection_get_devices;

    /// Gets the current IPv4 `nm.DhcpConfig` (if any) associated with the
    /// `nm.ActiveConnection`.
    extern fn nm_active_connection_get_dhcp4_config(p_connection: *ActiveConnection) *nm.DhcpConfig;
    pub const getDhcp4Config = nm_active_connection_get_dhcp4_config;

    /// Gets the current IPv6 `nm.DhcpConfig` (if any) associated with the
    /// `nm.ActiveConnection`.
    extern fn nm_active_connection_get_dhcp6_config(p_connection: *ActiveConnection) *nm.DhcpConfig;
    pub const getDhcp6Config = nm_active_connection_get_dhcp6_config;

    /// Gets the `nm.Connection`'s ID.
    extern fn nm_active_connection_get_id(p_connection: *ActiveConnection) [*:0]const u8;
    pub const getId = nm_active_connection_get_id;

    /// Gets the current IPv4 `nm.IPConfig` associated with the `nm.ActiveConnection`.
    extern fn nm_active_connection_get_ip4_config(p_connection: *ActiveConnection) *nm.IPConfig;
    pub const getIp4Config = nm_active_connection_get_ip4_config;

    /// Gets the current IPv6 `nm.IPConfig` associated with the `nm.ActiveConnection`.
    extern fn nm_active_connection_get_ip6_config(p_connection: *ActiveConnection) *nm.IPConfig;
    pub const getIp6Config = nm_active_connection_get_ip6_config;

    /// Gets the controller `nm.Device` of the connection.
    extern fn nm_active_connection_get_master(p_connection: *ActiveConnection) ?*anyopaque;
    pub const getMaster = nm_active_connection_get_master;

    /// Gets the path of the "specific object" used at activation.
    ///
    /// Currently, there is no single method that will allow you to automatically turn
    /// this into an appropriate `nm.Object`; you need to know what kind of object it
    /// is based on other information. (Eg, if `connection` corresponds to a Wi-Fi
    /// connection, then the specific object will be an `nm.AccessPoint`, and you can
    /// resolve it with `nm.DeviceWifi.getAccessPointByPath`.)
    extern fn nm_active_connection_get_specific_object_path(p_connection: *ActiveConnection) [*:0]const u8;
    pub const getSpecificObjectPath = nm_active_connection_get_specific_object_path;

    /// Gets the active connection's state.
    extern fn nm_active_connection_get_state(p_connection: *ActiveConnection) nm.ActiveConnectionState;
    pub const getState = nm_active_connection_get_state;

    /// Gets the active connection's state flags.
    extern fn nm_active_connection_get_state_flags(p_connection: *ActiveConnection) nm.ActivationStateFlags;
    pub const getStateFlags = nm_active_connection_get_state_flags;

    /// Gets the reason for active connection's state.
    extern fn nm_active_connection_get_state_reason(p_connection: *ActiveConnection) nm.ActiveConnectionStateReason;
    pub const getStateReason = nm_active_connection_get_state_reason;

    /// Gets the `nm.Connection`'s UUID.
    extern fn nm_active_connection_get_uuid(p_connection: *ActiveConnection) [*:0]const u8;
    pub const getUuid = nm_active_connection_get_uuid;

    /// Whether the active connection is a VPN connection.
    extern fn nm_active_connection_get_vpn(p_connection: *ActiveConnection) c_int;
    pub const getVpn = nm_active_connection_get_vpn;

    extern fn nm_active_connection_get_type() usize;
    pub const getGObjectType = nm_active_connection_get_type;

    extern fn g_object_ref(p_self: *nm.ActiveConnection) void;
    pub const ref = g_object_ref;

    extern fn g_object_unref(p_self: *nm.ActiveConnection) void;
    pub const unref = g_object_unref;

    pub fn as(p_instance: *ActiveConnection, comptime P_T: type) *P_T {
        return gobject.ext.as(P_T, p_instance);
    }

    test {
        @setEvalBranchQuota(100_000);
        std.testing.refAllDecls(@This());
    }
};

