/// NMClient contains a cache of the objects of NetworkManager's D-Bus API.
/// It uses `glib.MainContext` and `gio.DBusConnection` for that and registers to
/// D-Bus signals. That means, when iterating the associated `glib.MainContext`,
/// D-Bus signals gets processed and the `nm.Client` instance updates and
/// emits `gobject.Object` signals.
pub const Client = opaque {
    pub const Parent = gobject.Object;
    pub const Implements = [_]type{ gio.AsyncInitable, gio.Initable };
    pub const Class = nm.ClientClass;
    pub const virtual_methods = struct {};

    pub const properties = struct {
        /// The `nm.ActiveConnection` of the activating connection that is
        /// likely to become the new `nm.Client.properties.primary`-connection.
        pub const activating_connection = struct {
            pub const name = "activating-connection";

            pub const Type = ?*nm.ActiveConnection;
        };

        /// The active connections.
        pub const active_connections = struct {
            pub const name = "active-connections";

            pub const Type = ?[*]*nm.ActiveConnection;
        };

        /// List of both real devices and device placeholders.
        pub const all_devices = struct {
            pub const name = "all-devices";

            pub const Type = ?[*]*nm.Device;
        };

        /// If `TRUE`, adding and modifying connections is supported.
        pub const can_modify = struct {
            pub const name = "can-modify";

            pub const Type = c_int;
        };

        /// The list of capabilities numbers as guint32 or `NULL` if
        /// there are no capabilities. The numeric value correspond
        /// to `nm.Capability` enum.
        pub const capabilities = struct {
            pub const name = "capabilities";

            pub const Type = ?[*]u32;
        };

        /// The list of active checkpoints.
        pub const checkpoints = struct {
            pub const name = "checkpoints";

            pub const Type = ?[*]*nm.Checkpoint;
        };

        /// The list of configured connections that are available to the user. (Note
        /// that this differs from the underlying D-Bus property, which may also
        /// contain the object paths of connections that the user does not have
        /// permission to read the details of.)
        pub const connections = struct {
            pub const name = "connections";

            pub const Type = ?[*]*nm.RemoteConnection;
        };

        /// The network connectivity state.
        pub const connectivity = struct {
            pub const name = "connectivity";

            pub const Type = nm.ConnectivityState;
        };

        pub const connectivity_check_available = struct {
            pub const name = "connectivity-check-available";

            pub const Type = c_int;
        };

        pub const connectivity_check_enabled = struct {
            pub const name = "connectivity-check-enabled";

            pub const Type = c_int;
        };

        /// The used URI for connectivity checking.
        pub const connectivity_check_uri = struct {
            pub const name = "connectivity-check-uri";

            pub const Type = ?[*:0]u8;
        };

        /// The `gio.DBusConnection` to use.
        ///
        /// If this is not set during object construction, the D-Bus connection will
        /// automatically be chosen during async/sync initalization via `gio.busGet`.
        pub const dbus_connection = struct {
            pub const name = "dbus-connection";

            pub const Type = ?*gio.DBusConnection;
        };

        /// The name owner of the NetworkManager D-Bus service.
        pub const dbus_name_owner = struct {
            pub const name = "dbus-name-owner";

            pub const Type = ?[*:0]u8;
        };

        /// List of real network devices.  Does not include placeholder devices.
        pub const devices = struct {
            pub const name = "devices";

            pub const Type = ?[*]*nm.Device;
        };

        /// The current DNS configuration, represented as an array
        /// of `nm.DnsEntry` objects.
        pub const dns_configuration = struct {
            pub const name = "dns-configuration";

            pub const Type = ?[*]*nm.DnsEntry;
        };

        /// The current DNS processing mode.
        pub const dns_mode = struct {
            pub const name = "dns-mode";

            pub const Type = ?[*:0]u8;
        };

        /// The current resolv.conf management mode.
        pub const dns_rc_manager = struct {
            pub const name = "dns-rc-manager";

            pub const Type = ?[*:0]u8;
        };

        /// The machine hostname stored in persistent configuration. This can be
        /// modified by calling `nm.Client.saveHostname`.
        pub const hostname = struct {
            pub const name = "hostname";

            pub const Type = ?[*:0]u8;
        };

        /// `nm.ClientInstanceFlags` for the instance. These affect behavior of `nm.Client`.
        /// This is a construct property and you may only set most flags only during
        /// construction.
        ///
        /// The flag `NM_CLIENT_INSTANCE_FLAGS_NO_AUTO_FETCH_PERMISSIONS` can be toggled any time,
        /// even after constructing the instance. Note that you may want to watch NMClient:permissions-state
        /// property to know whether permissions are ready. Note that permissions are only fetched
        /// when NMClient has a D-Bus name owner.
        ///
        /// The flags `NM_CLIENT_INSTANCE_FLAGS_INITIALIZED_GOOD` and `NM_CLIENT_INSTANCE_FLAGS_INITIALIZED_BAD`
        /// cannot be set, however they will be returned by the getter after initialization completes.
        pub const instance_flags = struct {
            pub const name = "instance-flags";

            pub const Type = c_uint;
        };

        /// Whether the connectivity is metered.
        pub const metered = struct {
            pub const name = "metered";

            pub const Type = c_uint;
        };

        /// Whether networking is enabled.
        ///
        /// The property setter is a synchronous D-Bus call. This is deprecated since 1.22.
        pub const networking_enabled = struct {
            pub const name = "networking-enabled";

            pub const Type = c_int;
        };

        /// Whether the daemon is running.
        pub const nm_running = struct {
            pub const name = "nm-running";

            pub const Type = c_int;
        };

        /// The state of the cached permissions. The value `NM_TERNARY_DEFAULT`
        /// means that no permissions are yet received (or not yet requested).
        /// `NM_TERNARY_TRUE` means that permissions are received, cached and up
        /// to date. `NM_TERNARY_FALSE` means that permissions were received and are
        /// cached, but in the meantime a "CheckPermissions" signal was received
        /// that invalidated the cached permissions.
        /// Note that NMClient will always emit a notify::permissions-state signal
        /// when a "CheckPermissions" signal got received or after new permissions
        /// got received (that is regardless whether the value of the permission state
        /// actually changed). With this you can watch the permissions-state property
        /// to know whether the permissions are ready. Note that while NMClient has
        /// no D-Bus name owner, no permissions are fetched (and this property won't
        /// change).
        pub const permissions_state = struct {
            pub const name = "permissions-state";

            pub const Type = nm.Ternary;
        };

        /// The `nm.ActiveConnection` of the device with the default route;
        /// see `nm.Client.getPrimaryConnection` for more details.
        pub const primary_connection = struct {
            pub const name = "primary-connection";

            pub const Type = ?*nm.ActiveConnection;
        };

        /// Flags for radio interfaces. See `nm.RadioFlags`.
        pub const radio_flags = struct {
            pub const name = "radio-flags";

            pub const Type = c_uint;
        };

        /// Whether the daemon is still starting up.
        pub const startup = struct {
            pub const name = "startup";

            pub const Type = c_int;
        };

        /// The current daemon state.
        pub const state = struct {
            pub const name = "state";

            pub const Type = nm.State;
        };

        /// The NetworkManager version.
        pub const version = struct {
            pub const name = "version";

            pub const Type = ?[*:0]u8;
        };

        /// Expose version info and capabilities of NetworkManager. If non-empty,
        /// the first element is NM_VERSION, which encodes the version of the
        /// daemon as "(major << 16 | minor << 8 | micro)". The following elements
        /// is a bitfields of `nm.VersionInfoCapability`. If a bit is set, then
        /// the running NetworkManager has the respective capability.
        pub const version_info = struct {
