        /// and `NM_IP_TUNNEL_MODE_IP6GRETAP`
        pub const mode = struct {
            pub const name = "mode";

            pub const Type = c_uint;
        };

        /// If non-zero, only transmit packets of the specified size or smaller,
        /// breaking larger packets up into multiple fragments.
        pub const mtu = struct {
            pub const name = "mtu";

            pub const Type = c_uint;
        };

        /// The key used for tunnel output packets; the property is valid only for
        /// certain tunnel modes (GRE, IP6GRE). If empty, no key is used.
        pub const output_key = struct {
            pub const name = "output-key";

            pub const Type = ?[*:0]u8;
        };

        /// If given, specifies the parent interface name or parent connection UUID
        /// the new device will be bound to so that tunneled packets will only be
        /// routed via that interface.
        pub const parent = struct {
            pub const name = "parent";

            pub const Type = ?[*:0]u8;
        };

        /// Whether to enable Path MTU Discovery on this tunnel.
        pub const path_mtu_discovery = struct {
            pub const name = "path-mtu-discovery";

            pub const Type = c_int;
        };

        /// The remote endpoint of the tunnel; the value must contain an IPv4 or IPv6
        /// address.
        pub const remote = struct {
            pub const name = "remote";

            pub const Type = ?[*:0]u8;
        };

        /// The type of service (IPv4) or traffic class (IPv6) field to be set on
