            pub const name = "refuse-mschap";

            pub const Type = c_int;
        };

        /// If `TRUE`, the MSCHAPv2 authentication method will not be used.
        pub const refuse_mschapv2 = struct {
            pub const name = "refuse-mschapv2";

            pub const Type = c_int;
        };

        /// If `TRUE`, the PAP authentication method will not be used.
        pub const refuse_pap = struct {
            pub const name = "refuse-pap";

            pub const Type = c_int;
        };

        /// If `TRUE`, MPPE (Microsoft Point-to-Point Encryption) will be required for
