/// This is a hook to tweak the serialization.
///
/// Handler for certain properties or events that are not entirely contained
/// within the keyfile or that might be serialized differently. The `type` and
/// `handler_data` arguments tell which kind of argument we have at hand.
///
/// Currently only the type `NM_KEYFILE_HANDLER_TYPE_WRITE_CERT` is supported.
///
/// The callee may call `nm.KeyfileHandlerData.failWithError` to abort
/// the writing with error.
pub const KeyfileWriteHandler = *const fn (p_connection: *nm.Connection, p_keyfile: *glib.KeyFile, p_handler_type: nm.KeyfileHandlerType, p_handler_data: *nm.KeyfileHandlerData, p_user_data: ?*anyopaque) callconv(.c) c_int;

/// Called as a result of a request by NM to delete secrets.  When the
/// `nm.SecretAgentOld` subclass has finished deleting the secrets, this function
/// should be called.
pub const SecretAgentOldDeleteSecretsFunc = *const fn (p_agent: *nm.SecretAgentOld, p_connection: *nm.Connection, p_error: ?*glib.Error, p_user_data: ?*anyopaque) callconv(.c) void;

/// Called as a result of a request by NM to retrieve secrets.  When the
/// `nm.SecretAgentOld` subclass has finished retrieving secrets and is ready to
/// return them, or to return an error, this function should be called with
/// those secrets or the error.
///
/// To easily create the dictionary to return the Wi-Fi PSK, you could do
/// something like this:
/// <example>
///  <title>Creating a secrets dictionary</title>
///  <programlisting>
///   NMConnection *secrets;
///   NMSettingWirelessSecurity *s_wsec;
///   GVariant *secrets_dict;
///
///   secrets = nm_simple_connection_new ();
///   s_wsec = (NMSettingWirelessSecurity *) nm_setting_wireless_security_new ();
///   g_object_set (G_OBJECT (s_wsec),
///                 NM_SETTING_WIRELESS_SECURITY_PSK, "my really cool PSK",
///                 NULL);
///   nm_connection_add_setting (secrets, NM_SETTING (s_wsec));
///   secrets_dict = nm_connection_to_dbus (secrets, NM_CONNECTION_SERIALIZE_ALL);
///
///   (call the NMSecretAgentOldGetSecretsFunc with secrets_dict)
///
///   g_object_unref (secrets);
///   g_variant_unref (secrets_dict);
///  </programlisting>
/// </example>
pub const SecretAgentOldGetSecretsFunc = *const fn (p_agent: *nm.SecretAgentOld, p_connection: *nm.Connection, p_secrets: ?*glib.Variant, p_error: ?*glib.Error, p_user_data: ?*anyopaque) callconv(.c) void;

/// Called as a result of a request by NM to save secrets.  When the
/// `nm.SecretAgentOld` subclass has finished saving the secrets, this function
/// should be called.
pub const SecretAgentOldSaveSecretsFunc = *const fn (p_agent: *nm.SecretAgentOld, p_connection: *nm.Connection, p_error: ?*glib.Error, p_user_data: ?*anyopaque) callconv(.c) void;

